import requests
from dashboard.config import Config


class WeatherWidget:
    BASE_URL = 'https://api.openweathermap.org/data/2.5/weather'

    def __init__(self, city=None):
        self.api_key = Config.OPENWEATHERMAP_API_KEY
        self.city = city or Config.DEFAULT_CITY

    def fetch_current(self):
        """Fetch current weather data. Returns dict with temp, humidity, description."""
        if not self.api_key:
            raise ValueError('OPENWEATHERMAP_API_KEY not set')
        resp = requests.get(self.BASE_URL, params={
            'q': self.city,
            'appid': self.api_key,
            'units': 'metric'
        }, timeout=10)
        resp.raise_for_status()
        data = resp.json()
        return {
            'city': data['name'],
            'temp_celsius': data['main']['temp'],
            'humidity': data['main']['humidity'],
            'description': data['weather'][0]['description'],
            'icon': data['weather'][0]['icon']
        }

from flask import Flask, render_template
from dashboard.widgets.news import NewsWidget
from dashboard.widgets.weather import WeatherWidget

app = Flask(__name__)
news = NewsWidget()
weather = WeatherWidget()

@app.route('/')
def index():
    headlines = news.fetch_headlines()
    try:
        current_weather = weather.fetch_current()
    except Exception:
        current_weather = None
    return render_template('index.html', headlines=headlines, weather=current_weather)
